proc sql; 
create table soc as 
SELECT TJ7S.COMAX, TJ3P.COPFCI,  SUM(TJ8H.NBTITR) AS NBPS 
FROM ENT0.V2TJ7S AS TJ7S 
LEFT JOIN ENT0.V2TJ8H AS TJ8H ON TJ7S.COCO = SUBSTR(TJ8H.CONOPB,1,12) AND TJ8H.COETB = '009' AND TJ8H.CESITC IN ('1') AND TJ8H.DDVALE <= DATE() AND TJ8H.DFVALE > DATE() 
LEFT JOIN ESP0.TVALMOB AS VAL ON VAL.CVACT = TJ8H.CCVACT 
LEFT JOIN ENT0.V2TJ3P AS TJ3P ON TJ3P.COMAX = TJ7S.COMAX AND TJ3P.COETB = '009' AND TJ3P.CESITC IN ('1') AND TJ3P.DDVALE <= DATE() AND TJ3P.DFVALE > DATE() 
WHERE TJ7S.COETB = '009' AND TJ7S.CESITC IN ('1') 
AND TJ7S.COPRO IN ('00136','00137','00138','06212','06213','06214','06215','06216') 
AND TJ7S.DDVALE <=  DATE() AND TJ7S.DFVALE > DATE() 
/*having  nbps >0*/ 
GROUP BY 1,2; 
quit;

data soc; 
set soc; 
keep comax; 
run; 
